mats.system.loader.prototype.init_navigation = function() {

    var SELF = this;

	if (window.History && window.History.Adapter){
		window.History.Adapter.bind(window, 'statechange', function(){
			if (MANUAL_CONTENT_UPDATE){
				MANUAL_CONTENT_UPDATE = false;

				return;
			}

			var State = window.History.getState();

			for (var i = 0; i < SELF.navigate_back_callbacks.length; i++) { // call callbacks
                SELF.navigate_back_callbacks[i].call(SELF, i);
            }

			mats.system_misc.update_content(State.url, State.data, {no_history: true});
		});
	}

	$(document).on('click','a, input.internal_link_button',function(e) {
		var link = $(this);


		if (link.hasClass('back_button')){
			var parts = window.location.pathname.split('/');

			if (parts.length > 3) {
				// go to top level list page
				window.location = parts.slice(0, 3).join('/');
			} else if (parts.length == 3) {
				// already at top level list page, go to dashboard
				window.location = '/b/dashboard';
			} else if (window.History && window.History.Adapter){
				window.History.back();
			} else {
				window.history.go(-1);
			}
		}

		if (link.hasClass('modal_subpage')){
			return false;
		}

		if ($(this).hasClass('add-on') && !BUILD_EDITABLE){
			e.preventDefault();
			e.stopImmediatePropagation();
			return false;
		}

		var url = $(this).attr('href');

		if (link.hasClass('code_studio')){
			window.location = url;
			return true;
		}

		/* disable dynamic updates for ctrl+click and apple+click */
		if (e.metaKey || e.ctrlKey || (typeof(url) === 'undefined') || ($(this).attr('target') == '_blank') || $(this).hasClass('loader_overridden')){
			return true;
		}

		var url_details = mats.system_misc.parse_url(url);
		if (url_details.params.focus_widget_group){
			var focus_widget_group = $(this).closest('.page').find('.page_widget_group[data-widget_group_id="' + url_details.params.focus_widget_group + '"]');
			var widgets = focus_widget_group.find('.page_widget').filter(function(){ return $(this).closest('.page_widget_group').is(focus_widget_group); });

			if (focus_widget_group.data('persist_focus_record')){
				var storage = new mats.system_storage();

				var persisted_focus_record_ids = storage.get('persisted_focus_record_ids');
				if (!persisted_focus_record_ids){
					persisted_focus_record_ids = {};
				}

				persisted_focus_record_ids[url_details.params.focus_widget_group] = url_details.params.focus_record_id;

				storage.set('persisted_focus_record_ids', persisted_focus_record_ids);
			}

			if (widgets.length){
				if (widgets.offset().top < $('html, body').scrollTop()){
					widgets.scroll_to();
				}

				if (focus_widget_group.data('booking_record_options') && focus_widget_group.data('instance')){
					focus_widget_group.data('instance').ajax('collect_booking_record_options', {
						data: url_details.params,
						success: function(booking_record_options) {
							focus_widget_group.data('booking_record_options', booking_record_options);
						}
					});
				}

				widgets.each(function(){
					let widget_params = $(this).data('params') !== undefined ? $(this).data('params') : {};

					if(widget_params.settings !== undefined && $(this).closest('.page_widget_wrapper').hasClass('hidden') == true
					&& widget_params.settings.hide_empty !== undefined && widget_params.settings.hide_empty == 1){
						$(this).closest('.page_widget_wrapper').show();
						$(this).closest('.page_widget_wrapper').removeClass('hidden');
					}

					$(this).data('instance').reload({data: url_details.params, highlight:true});
				});
			}

			return false;
		}

		if (($(this).hasClass('record_link') || mats.system_misc.is_cs_record_link($(this))) && !$(this).closest('.modal').length){
			mats.system_misc.set_back_destination($(this).attr('href'));
		}

		if ($('form.page_widget_group.abandon_prompt.has_changes').length){
			return true;
		}

		var level = 4; // Content
		if ($(this).closest('.matssoft-navigation, #mobile-top-tabs').length ){ // Top tab
			level = 0;
		} else if ( $(this).closest('.mobile-pages').length ){ // Mobile page (must check before #mobile-menu due to nesting)
			level = 3;
		} else if ( $(this).closest('.matssoft-menu, #mobile-menu').length ) { // Sub tab
			level = 2;
		} else if ( $(this).closest('.matssoft-sub-menu').length ){ // Box menu
			level = 3;
		}

		// Close mobile nav if open
		$('#subnav-trigger.active').removeClass('active');

		var loader = mats.system_registry.instance.get('instances')['loader'];
		var url = loader.get_session_redirect(window.location.pathname, $(this).attr('href'), level, $(this).hasClass('no_history'));

		var is_same_deployment_link = true;
		if ($(this).attr('href').match(/^https?:\/\//)) {
			var system_address_check_regex = new RegExp('^' + SYSTEM_ADDRESS.replace(/[.?*+^$[\]\\(){}|-]/g, "\\$&"), 'i');

			if (!$(this).attr('href').match(system_address_check_regex)) {
				is_same_deployment_link = false;
			}
		}

		var dynamic_link_regex = new RegExp('\/(i\/[^\/]+\/p|w\\/webpage)\/(([0-9A-Za-z-])*?(\/)?)*');
		var interface_regex = /[iw]\/([\w_-]*)(?=\/)/;
		var popup_regex = new RegExp("^"+SYS_PATH + "popup\/([\w_-]*)");

		if (is_same_deployment_link
			&& window.location.pathname.match(dynamic_link_regex)
			&& $(this).attr('href').match(dynamic_link_regex)
			&& !$(this).is('.static_links')
			&& ((
				null !== window.location.pathname.match(interface_regex)
				&& null !== $(this).attr('href').match(interface_regex)
				&& window.location.pathname.match(interface_regex)[1] == $(this).attr('href').match(interface_regex)[1]) // destination and source pages shares the same interface
			) || (
				null !== popup_regex.exec($(this).attr('href'))
			)) {

			var maintain_position = url_details.params.maintain_position || null;

			if (maintain_position === null) {
				maintain_position = $(this).data('maintain_position') || null;
			}
			mats.system_misc.update_content(url, {}, {no_history: $(this).hasClass('no_history'), session_storage_key: $(this).attr('data-redirect_session_storage_key'), maintain_position: maintain_position});

			return false;

		} else {
			$(this).attr('href', url);
			if ((url != '#') && !$(this).hasClass('click_handler_assigned') && mats.system_test_studio.replaying_activity_instance){
				mats.system_test_studio.replaying_activity_instance.full_page_refresh_pending = true;
			}
		}
		return true;
	});

	$('#header_inner div.search input[type="text"]').preparePlaceholder();
	$('#header_inner div.search form').submit(mats.handle_placeholder_submit);

	// Back to top links
	if ($('.matssoft-footer-toplink').length){
		$('.matssoft-footer-toplink').topLink({
			min: 10,
			fadeSpeed: 500
		});

		$('.matssoft-footer-toplink button').click(function(e) {
			e.preventDefault();
			$(this).blur();

			$('html, body').stop().animate({
				scrollTop: 0
			}, 600);
		});
	}
};

mats.system.loader.prototype.init_top_search = function() {
	if (mobile_enabled) {
		$('.cd-search-overlay form').on('post_validation', function(e, submit_event){
			var url = mats.system_misc.get_location($(this).attr('action')).get_pathname();
			var fields = {};

			$(this).find('input[name^="top_search_fields["]:checked').each(function() {
				var parts = $(this).attr('name').split('[');

				var field_path = parts.pop();

				field_path = field_path.substr(0, field_path.length - 1);

				var object_id = parts.pop();

				object_id = object_id.substr(0, object_id.length - 1);

				if (typeof fields[object_id] === 'undefined') {
					fields[object_id] = {};
				}

				fields[object_id][field_path] = $(this).val();
			});

			var page_id = url.split('/').pop();

			var data = {
				page_id: page_id,
				fields: fields,
				string: misc.h($(this).find('[name="top_search_string"]').val())
			};

			var storage = new mats.system_storage(url);

			storage.set('top_search', data);
			storage.remove('request_data');
		});
	}
	else {
		$('.matssoft-search input[name="top_search_string"]').keydown(function(e){
			if ((e.keyCode == 13) && ($(this).val() != '')){
				var url = mats.system_misc.get_location($(this).closest('form').attr('action')).get_pathname();
				var fields = {};

				$(this).closest('form').find('input[name^="top_search_fields["]:checked').each(function() {

					var parts = $(this).attr('name').split('[');

					var field_path = parts.pop();

					field_path = field_path.substr(0, field_path.length - 1);

					var object_id = parts.pop();

					object_id = object_id.substr(0, object_id.length - 1);

					if (typeof fields[object_id] === 'undefined') {
						fields[object_id] = {};
					}

					fields[object_id][field_path] = $(this).val();
				});

				var page_id = url.split('/').pop();

				var data = {
					page_id: page_id,
					fields: fields,
					string: misc.h($(this).val())
				};

				var storage = new mats.system_storage(url);

				storage.set('top_search', data);
				storage.remove('request_data');

				$(this).closest('form').submit();
			}
		});

		var top_search_popup = $('header .search-dialog');
		if (top_search_popup.length){
			top_search_popup.css('max-height', (window.innerHeight - $('header').height()) + 'px');
			window.addEventListener('resize', function(){
				top_search_popup.css('max-height', (window.innerHeight - $('header').height()) + 'px');
			});
		}
	}
};

mats.system.loader.prototype.init_notifications = function() {

    var SELF = this;

	if(IS_MOBILE_APP){
		return;
	}

    if (SELF.notification_module_enabled) {

        if ((0 != document.URL.indexOf('/login')) && (PAGE_ENVIRONMENT != 'webpage') && ($('.app-header .icon-toolkit .icon-toolkit-me .badge').length > 0)) {

            var thread = setInterval(function(){
                $.ajax({
                    url: mats.system_misc.normalise_url('notification_count'),
                    type: 'post',
                    data: {
                        current_notification_count: $('.app-header .icon-toolkit .icon-toolkit-me .badge').text()	//#header-bar .matssoft-avatar .badge
                    },
                    success: function(result){

                        try {

                            if (mats.system_misc.i(result) == result) {
                                $('.app-header .icon-toolkit .icon-toolkit-me .badge').text(result);
                            }

                        } catch (e) {
                            clearInterval(thread);
                        }
                    }
                });

            }, 60000);
        }
    }
};

mats.system.loader.prototype.init_toolbar_icons = function() {

	var SELF = this;

	if(IS_MOBILE_APP){
		return;
	}

	var default_frequency = 0;
	var current_toolbar_icons = {0:[],15:[],30:[],45:[]};

	$('span[data-toolbaricon_id^="TBI"]').each(function(e) {
		var freq = $(this).data("update");
		if ( default_frequency ==0 || freq < default_frequency   ){
			default_frequency = freq;
		}
		switch (freq) {
			case 15:
				current_toolbar_icons[15][e] = $(this).data("toolbaricon_id");
				current_toolbar_icons[45][e] = $(this).data("toolbaricon_id");
			case 30:
				current_toolbar_icons[30][e] = $(this).data("toolbaricon_id");
			default:
				current_toolbar_icons[0][e] = $(this).data("toolbaricon_id");
				break;
		}

	});

	var update_frequency = (default_frequency >= 15) ?  default_frequency*1000 : 30000;

	if (default_frequency > 0) {

		if ((0 != document.URL.indexOf('/login')) && (PAGE_ENVIRONMENT != 'webpage')) {
			var count = 0;
			var thread = setInterval(function(){
				if (this.session_expired === true) {
					clearInterval(thread);
				} else {
					count = (count + default_frequency) % 60 ;
					$.ajax({
						url: mats.system_misc.normalise_url('toolbar_icons_count'),
						suppress_default_redirect: true,
						type: 'post',
						data: {
							current_toolbar_icons: JSON.stringify(current_toolbar_icons[count])
						},
						success: function(result){
							try {

								if (typeof JSON.parse(result) == 'object') {
									$.each(JSON.parse(result), function (k, v){
										if (typeof v != 'boolean'){
											v = parseInt(v);
											$("span[data-toolbaricon_id=" + k ).text(v >= 100 ? "99+" : v);
										} else if ( v === true && $("span[data-toolbaricon_id='"+k+"']").hasClass('hidden')){
											$("span[data-toolbaricon_id=" + k ).removeClass('hidden');
										} else if (v === false){
											$("span[data-toolbaricon_id=" + k ).addClass('hidden');
										}
									});

									var hamburger_status = false;
									$('span[data-toolbaricon_id^="TBI"]').each(function(e) {
										if (!($(this).hasClass('hidden')) ) { // Is visible
											if ($(this).is(':empty') || parseInt($(this).text()) > 0 ){
												hamburger_status = true;
											}
										}
									});

									if ( hamburger_status === true && $('span[data-toolbaricon_id="navbar-tbi-toggler"]').hasClass('hidden')){
										$('span[data-toolbaricon_id="navbar-tbi-toggler"]').removeClass('hidden');
									} else if (hamburger_status === false){
										$('span[data-toolbaricon_id="navbar-tbi-toggler"]').addClass('hidden');
									}
								}
							} catch (e) {
								clearInterval(thread);
							}
						},
						error: function (){
							clearInterval(thread);
							this.session_expired = true;
							// might not even need this given the system handles the expiration anyway
							if (SESSION_EXPIRY_CHECK) {
								mats.system_misc.reload_expired_session();
							}
						}
					});
				}
			}, update_frequency);
		}
	}
}

mats.system.loader.prototype.prepare_viewed_record = function(url_details){
	var storage = new mats.system_storage_global();
	var current_viewed_record_id = storage.get('viewed_record_id');

	if (url_details.params.context_record_id){
		if (current_viewed_record_id != url_details.params.context_record_id){
			storage.set('viewed_record_id', url_details.params.context_record_id);
		}

		return url_details.params.context_record_id;
	}
	else if (current_viewed_record_id) {
		storage.remove('viewed_record_id');
	}

	return null;
};

mats.system.loader.prototype.init_global_event_handlers = function() {

	// Tipbox Popovers Hide Handler
	$(document).click(function (e) { // Hide tipbox if clicked outside trigger
		$('.tipbox').hide();
	});

	// Fix Tipbox Popover when it has a negative top/left offset
	$(document).on('shown.bs.popover', function(e){
		if ($(e.target).data('bs.popover')){
			var popover = $($(e.target).data('bs.popover').tip);
			if (popover.length == 1) {
				if (popover.hasClass('field_history_popover')) {
					var offset = popover.offset();
					if (offset.top < 0) {
						popover.css('top', '20px');
					}
					if (offset.left < 0) {
						popover.css('left', '20px');
					}
				}
			}
		}
	});

	$(document).keyup(function(e) { // Hide tipbox on escape
		if (e.keyCode == 27) {
			$('.tipbox').hide();
		}
	});

};

mats.system.loader.prototype.evaluate_single_use_filters = function(url, params){
	if (!params){
		params = {};
	}

	var SELF = this;
	var destination_storage_key = mats.system_misc.get_location(url).get_pathname();
	var global_storage = new mats.system_storage_global();
	var single_use_filters = global_storage.get('single_use_filters');
	if (single_use_filters) {
		$.each(single_use_filters, function (path) {
			if (params.popup_only && !path.match(/\/popup\//)){
				return;
			}

			if ((path !== destination_storage_key) || (params.session_storage_key && (path != params.session_storage_key))) {

				var page_store = new mats.system_storage(path);

				if (page_store) {
					var filters = page_store.get('filters');

					$.each(single_use_filters[path], function(key, path_elem) {
						try {
							if (typeof(path_elem.context_relation_path) != 'undefined'){
								delete filters['defined']['special'][path_elem['base_object_id']]['relations'];
							}
							else if (typeof(path_elem.sub_context_relation_path) != 'undefined'){
								delete filters['defined']['special']['sub_context'];
							}
							else {
								delete filters['defined'][path_elem['base_object_id']][path_elem['relation_path']][path_elem['page_id']][path_elem['cell_id']];
								delete filters['submitted_values'][path_elem['cell_id']];
							}
						} catch (e) {}
					});

					if (typeof(filters) == 'object'){
						if (typeof(filters['special_filters_to_ignore']) != 'undefined'){
							delete filters['special_filters_to_ignore'];
						}

						filters = SELF.recursively_tidy_filters(filters);
					}

					page_store.set('filters', filters);

					delete single_use_filters[path];
					global_storage.set('single_use_filters', single_use_filters)
				}
			}
		});
	}
}

mats.system.loader.prototype.recursively_tidy_filters = function(filters) {
	var SELF = this;

	$.each(filters, function(key, value) {
		if (typeof(value) == 'object'){
			filters[key] = SELF.recursively_tidy_filters(value);

			if (filters[key] === null){
				delete filters[key];
			}
		}
	});

	return $.isEmptyObject(filters)? null : filters;
};

mats.system.loader.prototype.update_content = function(url, post_data, params) {
	window.define = null;
	if (typeof(post_data) == 'undefined') {
		post_data = {};
	}
	if (typeof(params) == 'undefined') {
		params = {};
	}

	/*
	#34769 - If a widget group has the abandon prompt option enabled, we need to keep the user on the same page
	when they use the browser's back, forward, or refresh buttons and click "Cancel" on the leave prompt.
	This is necessary when navigating from an internal app, as beforeunload will not be triggered in that case.
	*/
	if ($('form.page_widget_group.abandon_prompt.system_form.has_changes').length && !post_data['submission_token'] && !params.modal && !params.reset_button_clicked) {
		if (!confirm(mats.system_misc.label('abandon_prompt'))) {
			// User clicked cancel in leaving prompt, so do not proceed and stay on this page.
			return false;
		}
	}

	var SELF = this;

	if (typeof(tmpl) != 'undefined'){
		tmpl.cache = {};
	}

    this.target_url = url;
    this.submitted_post_data = post_data;

	if (!params.modal && !params.retain_modal) {
		if (!mats.system_misc.is_popup_link(url)){
			$('body > .modal').each(function(){
				$(this).modal('hide');
			});
		}
		else {
			var modal = $('body > .modal.show:visible');
			if (modal.length) {
				modal.modal('hide');
			}
		}
	}

	$('body > .popover.show:visible').remove();

	var pdf_export_popup = null;
	if (params.generate_pdf) {
		pdf_export_popup = new mats.system_popup('Your PDF is being generated, please wait...', 'Generating PDF');
	}

	var REQUEST_ID = mats.system_misc.unique_id('ajax_load');
	SELF.last_request_id = REQUEST_ID;

	if (! params.generate_pdf) {
		for (var i = 0; i < SELF.before_content_update_callbacks.length; i++) {
			SELF.before_content_update_callbacks[i].call(SELF, i);
		}
	}

	url = mats.system_misc.normalise_url(url);

	var registry = mats.system_registry.instance.contextualise($(document));

	var destination_storage_key = mats.system_misc.get_location(url).get_pathname();

	var global_storage = new mats.system_storage_global();
	var source_storage = new mats.system_storage();
	var destination_storage = new mats.system_storage(destination_storage_key);

	SELF.evaluate_single_use_filters(url, params);

	if (typeof post_data['_submit'] !== 'undefined') { // when form submitted
		destination_storage.remove('top_search'); // delete top search settings

		var destination_storage_data = destination_storage.get_data();

		for (var l in destination_storage_data) { // reset destination page pagination
			if (0 == l.indexOf('cell_')) {
				var cell_storage = new mats.system_storage(destination_storage_key, l);

				if (cell_storage.has('pagination_start_offset')) {
					cell_storage.set('pagination_start_offset', 0);
				}
			}
		}
	}

	if (destination_storage.has('top_search') && !$.isEmptyObject(destination_storage.get('top_search'))) { // top search has been performed
		if (destination_storage.has('filters')) { // performed search on this page using form
			destination_storage.remove('filters');
		}
	}

	var session_storage_data = {};

	var destination_storage_data = destination_storage.get_data();
	if (!$.isEmptyObject(destination_storage_data)) {
		session_storage_data[destination_storage.index] = destination_storage_data;
	}

	var fixed_storage_data = global_storage.get_data();
	if (fixed_storage_data){
		session_storage_data._global = fixed_storage_data;
	}

	if (params.session_storage_key) {
		var additional_destination_storage = new mats.system_storage(params.session_storage_key);

		var additional_destination_storage_data = additional_destination_storage.get_data();
		if (!$.isEmptyObject(additional_destination_storage_data)) {
			session_storage_data[params.session_storage_key] = additional_destination_storage_data;
		}
	}

	if (!$.isEmptyObject(session_storage_data)) {
		post_data._session_storage = JSON.stringify(session_storage_data);
	}

	var url_details = mats.system_misc.parse_url(url);
	if (url_details.nav){
		var current_viewed_record_id = global_storage.get('viewed_record_id');
		var new_viewed_record_id = SELF.prepare_viewed_record(url_details);
		if (current_viewed_record_id && (current_viewed_record_id == new_viewed_record_id)){
			post_data['viewed_record_id'] = url_details.params.context_record_id;
		}

		var viewport_subset_map = global_storage.get('viewport_subset_map');
		viewport_subset_map = viewport_subset_map? viewport_subset_map : {};
		var viewport_id = url_details.nav.viewport_id;

		var from_subset_id = url_details.params.from_subset_id;
		if (!from_subset_id && (url_details.params.widget_action == 'get_next')){
			from_subset_id = url_details.params.subset_id;

			var destination_url_details = mats.system_misc.parse_url(decodeURIComponent(url_details.params.destination));
			viewport_id = destination_url_details.nav.viewport_id;
		}

		if (from_subset_id){
			post_data['from_subset_id'] = viewport_subset_map[viewport_id] = from_subset_id;
		}
		else if (viewport_subset_map[viewport_id]){
			if (url_details.params.context_record_id){
				post_data['from_subset_id'] = viewport_subset_map[viewport_id];
			}
			else {
				delete viewport_subset_map[viewport_id];
			}
		}

		if (!$.isEmptyObject(viewport_subset_map)){
			global_storage.set('viewport_subset_map', viewport_subset_map);
		}
		else {
			global_storage.remove('viewport_subset_map');
		}
	}

	mats.system_module_contextmenu?.destroy();
	post_data._update_page_content_request = 1;

	if ($('#mats_content_wrapper').hasClass('page_full_screen')) {
		post_data._fsm = 1;
	}

	$.ajax({
		url: url,
		type: 'POST',
		data: post_data,
		dataType: 'json',
		suppress_error_handling: true,
		show_load_indicator: true,
		success: function(data, textStatus, xhr) {
			if (typeof CollectGarbage === 'function') {
			    CollectGarbage();
			}

			if (SELF.last_request_id != REQUEST_ID){
				return false;
			}

			if (params.generate_pdf) {
				if (!data.file_name) {
					return false;
				}

				window.location = SYS_PATH + 'file_serve?subject=pdf&file=' + encodeURI(data.file_name) + '&filename=' + encodeURI(window.document.title + '.pdf');
				return false;
			}

			if(data != null && data.page !== undefined && data.page.id !== undefined) {
				$('body').attr('data-page-id', data.page.id);
			}

			if(data != null && data.page !== undefined) {
				let p = url.split('/');
				let body_id = p[p.length - 1].replace(/[^a-zA-Z_0-9]/, '');

				if (!isNaN(body_id.substring(0, 1))) {
					body_id = body_id.substring(1);
				}
				let page_id = data.page.custom_body_id || body_id;
				$('body').attr('id', 'page-' + page_id);
			}

			var content = (params.modal && data.page && (data.page.type == 'popup'))? params.modal.find('.modal-body .modal-text-wrapper') : $('#content'); // content container

			var content_loaded_type = ['page'];
			if (content.is('#content')) {
				hugerte.remove();
				content_loaded_type.push('navigation_page');
			}

			if (params.modal && data.page && (data.page.type != 'popup')) {
				$('body > .modal.show:visible').modal('hide');
			}

			content.find('form.has_changes').removeClass('has_changes');

			if (false !== data && typeof data['status'] === 'string') {
				if ((data['status'] == 'redirect') && data.redirect_url) {
					if (mats.system_test_studio.replaying_activity_instance){
						mats.system_test_studio.replaying_activity_instance.full_page_refresh_pending = true;
					}
					window.location = data.redirect_url;
					return;
				}
				else if ('success' == data['status']) {
					if (data.redirect_url) {
						if (mats.system_test_studio.replaying_activity_instance){
							mats.system_test_studio.replaying_activity_instance.full_page_refresh_pending = true;
						}
						window.location = data.redirect_url;
						return;
					}

					if (typeof(data['data']) != 'undefined'){
						content.html(data['data']);
					}
					else if (typeof(data['html']) != 'undefined'){
						// This condition shouldn't be required, but reloading modal sends back the HTML under "html" key, instead of "data".
						content.html(data['html']);
					}

					if (params.modal && data.page && (data.page.type == 'popup') && params.modal.data('instance') && params.modal.find('form').length && !params.modal.find('form').hasClass('popup_init_complete')) {
						params.modal.data('instance').init_form();
					}

				}
				else if ('logged_out' == data['status']) {
					window.location.href = SYS_PATH + 'login';
					return;
				}
				else {
					content.html(data['data']);
					return;
				}
			}

			if (post_data.maintain_position) {
				params.maintain_position = 1;
			}
			//#15297 Only add the navigation to the core nav element
			// #28075 Change the selector to help reduce code studio modules accidentally using it.
			$('[data-liberty-create-id="sidebar-nav"]').each(function(){
				$(this).update(data['navigation_rendered']);
			});

			if (typeof(data['toolbar_icons']) != 'undefined'){
				if($('.custom_header').length == 1){ // Theme pack toolbar icons will be updated by the theme pack itself
					$('.custom_header').addClass('content_updated');
				}else{
					var toolbar_icons_container = $('header .nav.navbar-nav[role="menubar"]');
					toolbar_icons_container.find('.toolbar_icon').remove();
					toolbar_icons_container.prepend(data['toolbar_icons']);
					toolbar_icons_container.find('.toolbar_icon').content_loaded();
				}
			}

			content.content_loaded(content_loaded_type, params.maintain_position || null);

			for (var i = 0; i < SELF.after_content_update_callbacks.length; i++) { // call callbacks
				SELF.after_content_update_callbacks[i].call(SELF, i);
			}

			// do we need to reload the whole page once the ajax call is complete?
			if ( (params.whole_page_reload == 1) || (post_data.whole_page_reload == 1) ) {
				if (mats.system_test_studio.replaying_activity_instance){
					mats.system_test_studio.replaying_activity_instance.full_page_refresh_pending = true;
				}
				setTimeout(function(){
					window.location.reload();
				});
			}
			if (data.accessibility_settings){
				for (let setting in data.accessibility_settings) {
					if (data.accessibility_settings[setting] == 1){
						if(!$("body").hasClass(setting)){
							$("body").addClass(setting);
						}
					} else {
						if($("body").hasClass(setting)){
							$("body").removeClass(setting);
						}
					}
				  }
			}
			$('body > #ui-datepicker-div:visible').hide();
		},
		error: function(jqXHR, text_status, error_thrown) {
			if (jqXHR.responseJSON && (typeof(jqXHR.responseJSON.page) != 'undefined') && (typeof(jqXHR.responseJSON.status) != 'undefined') && (jqXHR.responseJSON.status == 'noaccess')){
				var data = jqXHR.responseJSON;
				var content = (params.modal && data.page && (data.page.type == 'popup'))? params.modal.find('.modal-body .modal-text-wrapper') : $('#content'); // content container

				if (params.modal && data.page && (data.page.type != 'popup')) {
					$('body > .modal.show:visible').modal('hide');
				}

				if (typeof(data['data']) != 'undefined'){
					content.html(data['data']);
				}
				else if (typeof(data['html']) != 'undefined'){
					content.html(data['html']);
				}

				if (typeof(data['navigation_rendered'] != 'undefined')){
					// #28075 Change the selector to help reduce code studio modules accidentally using it.
					$('[data-liberty-create-id="sidebar-nav"]').each(function(){
						$(this).update(data['navigation_rendered']);
					});
				}
			}

		    if (!jqXHR.responseText) {
		        console.dev_log(error_thrown);

		        return;
		    }
		},
		complete: function(xhr, status){
			var global_storage = new mats.system_storage_global();

			if (pdf_export_popup){
				pdf_export_popup.hide();
			}

			if (status == 'error') {
				var matches_crash_identifier = xhr.responseText? xhr.responseText.match(/!!(C[0-9]{3}_[0-9]{8}_[0-9]{6})!!/) : null;
				if (matches_crash_identifier) {
					new mats.system_ajax('get_error_details', {
						data: {
							real_url: url,
							include_headers: 1,
							identifier: matches_crash_identifier[1]
						},
						dataType: 'json',
						suppress_error_handling: true,
						success: function(data){
							var content = (params.modal && data.page && (data.page.type == 'popup'))? params.modal.find('.modal-body .modal-text-wrapper') : $('#content'); // content container

							var content_loaded_type = ['page'];
							if (content.is('#content')) {
								content_loaded_type.push('navigation_page');
							}

							if (params.modal && data.page && (data.page.type != 'popup')) {
								$('body > .modal.show:visible').modal('hide');
							}

							content.update(data.html, content_loaded_type);

							if (data.page && (data.page.type == 'popup')) {
								params.modal.find('.modal-footer:visible').each(function(){
									$(this).find('a.disabled').removeClass('disabled');
									$(this).find('.modal_saving_banner').remove();
								});
							}
							else {
								SELF.update_navigation(url, params);
							}
						}
					});
				}
			}
			else if (status == 'success'){
				if (params.modal && xhr.responseJSON && xhr.responseJSON.page && (xhr.responseJSON.page.type == 'popup')){
					params.modal.find('.modal-footer:visible').each(function(){
						$(this).find('a.disabled').removeClass('disabled');
						$(this).find('.modal_saving_banner').remove();
					});
				}
				else {
					SELF.update_navigation(url, params);

					var current_page_has_context_record = (parseInt(CONTEXT_RECORD_ID) > 0);

					if ((current_page_has_context_record && (!global_storage.get('last_context_record_id') || (parseInt(global_storage.get('last_context_record_id')) != CONTEXT_RECORD_ID)))
						|| (!current_page_has_context_record && (typeof(post_data.submitted_widget_group_type) != 'undefined') && (post_data.submitted_widget_group_type == 'modify'))
					){
						if (current_page_has_context_record){
							global_storage.set('last_context_record_id', CONTEXT_RECORD_ID);
						}

						if(!SELF.recent_records_history){
							SELF.recent_records_history = new mats.system_module_recent_records_history();
						}
						SELF.recent_records_history.refresh();
					}

					$(document).trigger('mats-page-change');
				}

				if (params.callback) {
					params.callback();
				}
			}
		},
		statusCode: {
			404: function() {
				document.dispatchEvent(new CustomEvent('has_404', {
					detail: {
						url,
					}
				}));
			}
		}
	});
};

mats.system.loader.prototype.update_navigation = function(url, params) {
	var SELF = this;

	var global_storage = new mats.system_storage_global();

	var destination_stack = global_storage.get('destination_stack');
	if (!$.isArray(destination_stack)){
		destination_stack = [];
	}
	if (!destination_stack.length || (destination_stack[0] != CLEAN_URL)){
		if (destination_stack.unshift(CLEAN_URL) > 10){
			destination_stack.pop();
		}
	}
	global_storage.set('destination_stack', destination_stack);

	var back_destination = global_storage.get('back_destination');
	if (back_destination){
		var current_viewport_links = [];
		if (back_destination.viewports[VIEWPORT_ID]) {
			current_viewport_links = $.isArray(back_destination.viewports[VIEWPORT_ID])? back_destination.viewports[VIEWPORT_ID] : [back_destination.viewports[VIEWPORT_ID]];
		}

		if (back_destination.current){
			current_viewport_links.unshift(back_destination.current);

			back_destination.current = null;
			back_destination.viewports[VIEWPORT_ID] = current_viewport_links;

			global_storage.set('back_destination', back_destination);
		}
		if (back_destination.last_used){
			if (back_destination.viewports[back_destination.last_used.viewport_id]
				&& (back_destination.viewports[back_destination.last_used.viewport_id][0] == back_destination.last_used.url)
				&& (back_destination.last_used.url == CLEAN_URL)
			){
				back_destination.viewports[back_destination.last_used.viewport_id].shift();
			}
			back_destination.last_used = null;
			global_storage.set('back_destination', back_destination);
		}

		if (current_viewport_links.length && parseInt(CONTEXT_RECORD_ID)){
			if ($('#back_link_holder')[0]){
				$('#back_link_holder .back_link').remove();
				var back_link = $('<a class="btn btn-back mb-2 back_link" data-ts_interaction="mats_back_link" href="' + SYS_PATH + current_viewport_links[0] + '"><span> ' + h(mats.system_misc.label('back')) + '</span></a>')
					.click(function(){
						var back_destination = global_storage.get('back_destination');
						back_destination.last_used = {viewport_id: VIEWPORT_ID, url: current_viewport_links[0]};
						global_storage.set('back_destination', back_destination);
					})
					.prependTo($('#back_link_holder'));

				mats.system_test_studio.apply(back_link);
			}
		}
	}

	var url_details = mats.system_misc.parse_url(CLEAN_URL);
	if (url_details.nav){
		SELF.prepare_viewed_record(url_details);
	}

	if (!params.no_history || (mats.system_misc.normalise_url(url) != mats.system_misc.normalise_url(CLEAN_URL))){
		SELF.change_url();
	}

	// Update window title
	if ($("#page_title").length) {
		window.document.title = $("#page_title").val();
