			mobileTitle = mats.system_misc.label('application_name');
		}
		$("#mobile-header h2").html(mobileTitle);
	}

}

mats.system.loader.prototype.change_url = function() {

    var SELF = this;

    MANUAL_CONTENT_UPDATE = true;

    var history_url = $("#content").find('#_url_replacement').length? $("#content").find('#_url_replacement').val() : CLEAN_URL;

    for (var i = 0; i < SELF.before_url_change_callbacks.length; i++) {
        history_url = SELF.before_url_change_callbacks[i].call(SELF, history_url, i);
    }

	if (!mats.system_misc.browser()['msie'] // not IE
		|| (mats.system_misc.browser()['msie'] && 9 < parseInt(mats.system_misc.browser().version))) { // or IE > 9

		history_url = '/' == history_url[0] ? history_url : SYS_PATH + history_url;
	}

	window.History.pushState(null, null, history_url);

    SELF.update_top_tabs(history_url);
};

mats.system.loader.prototype.update_top_tabs = function(url) {

	var SELF = this;
	var matches = /p\/([0-9A-Za-z-]+)\//gi.exec(url);

	if (null !== matches) {

		var top_tab_id = matches[1];

		$('.matssoft-navigation li a, #mobile-top-tabs li a').each(function(){
			var href = $(this).attr('href');
			var link_matches = /p\/([0-9A-Za-z-]+)\//gi.exec(href);

			if (link_matches && (top_tab_id == link_matches[1])){
				$('.matssoft-navigation li.active, #mobile-top-tabs li.active').removeClass('active');

				var li = $(this).closest('li');
				li.addClass('active').removeClass('hidden');

				var siblings = li.siblings('li.not_visible');
				siblings.addClass('hidden');
			}
		});
	}
};

mats.system.loader.prototype.get_session_redirect = function(source_url, target_url, level, no_history) {

	  /* p/x/x/x/x */
		var regex = /([A-Za-z\_]+)\/p\/([0-9A-Za-z-]+)\/([0-9A-Za-z-]+)\/([0-9A-Za-z-]+)\/([0-9A-Za-z-]+)(\?.+)?/gi;
		var url = target_url;
		var save_to_session = REMEMBER_LAST_PAGE && !no_history;

		if(typeof(Storage)!=="undefined" ) {
			var matches = regex.exec(target_url);

			/* Found cached history */
			if (sessionStorage.tabHistory && REMEMBER_LAST_PAGE) {
				var navigation = sessionStorage.getItem('tabHistory');
				navigation = navigation.to_clean_object();
			}
			/* Create new history cache */
			else {
				var navigation = new Object();
				navigation['top_tab'] = new Object(); // Top tab
				navigation['viewport'] = new Object(); // View
				navigation['sub_tab'] = new Object(); // Sub tab
				navigation['build_top_tab'] = new Object(); // Top tab for Build
				navigation['build_sub_tab'] = new Object(); // Sub tab for Build
				navigation['last_page'] = new Object(); // Last page
			}

			/* going to p/x/x/x/ */
			if (matches){
				var target_interface =  matches[1];
				var l1 = matches[2];
				var l2 = matches[3];
				var l3 = matches[4];
				var l4 = matches[5];
				var params = (typeof matches[6] === 'undefined')? '': matches[6];
				var redirect = false;

				var	s_regex = /([A-Za-z\_]+)\/?p\/([0-9A-Za-z-]+)\/([0-9A-Za-z-]+)\/([0-9A-Za-z-]+)\/([0-9A-Za-z-]+)(\?.+)?/gi;
				var s_matches = s_regex.exec(source_url);
				if (s_matches){
					var source_interface =  s_matches[1];
					var s1 = s_matches[2];
					var s2 = s_matches[3];
					var s3 = s_matches[4];
				} else {
					var source_interface =  '';
					var s1 = 0;
					var s2 = 0;
					var s3 = 0;
				}

				if ((target_interface != source_interface) || (level == 0 && l1 == s1)){
					url = target_url;
				}
				/* Top tab click and cached last page */
				else if (level == 0 && l1 != s1 && navigation['top_tab'][l1] && navigation['top_tab'][l1][target_interface]){
					url = navigation['top_tab'][l1][target_interface];
					redirect = true;

				}
				/* Sub tab click and cached last page */
				else if(l1 == s2 && l2 == s2 && l3 != s3 && navigation['sub_tab'][l3] && navigation['top_tab'][l3][target_interface] && !params){
					url = navigation['sub_tab'][l3][target_interface];
				}

					if (typeof(navigation['top_tab'][l1]) != 'object'){
						navigation['top_tab'][l1] = new Object();
					}

					if (typeof(navigation['viewport'][l2]) != 'object'){
						navigation['viewport'][l2] = new Object();
					}

					if (typeof(navigation['sub_tab'][l3]) != 'object'){
						navigation['sub_tab'][l3] = new Object();
					}
				if (!redirect ){

					navigation['top_tab'][l1][target_interface] = url;
					navigation['viewport'][l2][target_interface] = url;
					navigation['sub_tab'][l3][target_interface] = url;
				}
			}
			/* Build area */
			else if ((level < 4) && !/\/i\/(.+)/.exec(target_url)){
				var build_regex = /b\/(.*)/;
				if (!build_regex.exec(target_url)){
					target_url = SYS_PATH+'b/' + target_url;
				}
				var sub_tab = $('.sub_tabs_admin li.active a').attr('href');

				/* Top tab 'Build' and cached last page */
				if (level == 0 && navigation['build_top_tab'].length ){
					if (source_url != '/' + navigation['build_top_tab']){
						url =  navigation['build_top_tab'];
					}
				}
				/* Sub tab click and cached last page */
				else if(level == 2  ){
					navigation['build_top_tab'] = target_url;
					if (typeof(navigation['build_sub_tab'][target_url]) != 'undefined' &&  target_url != navigation['build_sub_tab'][target_url]){
						navigation['build_top_tab'] = navigation['build_sub_tab'][target_url];
						url =  navigation['build_sub_tab'][target_url];
					}
				} else {
					navigation['build_top_tab'] = target_url;
					if ( sub_tab ){
						if (typeof(navigation['build_sub_tab'][sub_tab]) != 'object'){
							navigation['build_sub_tab'][sub_tab] = new String();
						}
						navigation['build_sub_tab'][sub_tab] = navigation['build_top_tab'];
					}
				}
				if (!$('body').hasClass('build-environment')){
					save_to_session = false;
				}
			}

			if (!redirect && save_to_session){
				navigation['last_page'] = target_url;
				sessionStorage.setItem('tabHistory', JSON.stringify(navigation));
			}
		}

		return url;
};

mats.system.loader.prototype.drop_last_session_redirect = function() {

	/* Found cached history */
	if (sessionStorage.tabHistory) {
		var navigation = sessionStorage.getItem('tabHistory');
		navigation = navigation.to_clean_object();
		var last_page = navigation['last_page'];
		if (last_page == navigation['build_top_tab']){
			navigation['build_top_tab'] = new Object();
		}

		$.each(['top_tab','viewport','sub_tab','build_sub_tab'], function(idx, val) {
			$.each(navigation[val], function(interface_index, interface_name) {
				$.each(navigation[val][interface_index], function(index, value) {
					if (last_page == value){
						delete navigation[val][interface_index][index];
					}
				});
			});
		});

		sessionStorage.setItem('tabHistory', JSON.stringify(navigation));
	}
};

mats.system.loader.prototype.init_session_expiry_check = function() {
	if(IS_MOBILE_APP){
		return;
	}

	if (SESSION_EXPIRY_CHECK && (document.URL.indexOf('/login') < 0)) {

		if (PAGE_ENVIRONMENT != 'webpage') {

			let update_frequency = 60000; // Run check every minute
			let thread = setInterval(function () {
				if (this.session_expired === true) {
					clearInterval(thread);
				} else {
					$.ajax({
						url: mats.system_misc.normalise_url('session_check'),
						suppress_default_redirect: true,
						type: 'GET',
						data: {},
						success: function (result) {
							try {
								if (typeof JSON.parse(result) != 'object') {
									clearInterval(thread);
									this.session_expired = true;
									mats.system_misc.reload_expired_session();
								}
							} catch (e) {
								clearInterval(thread);
							}
						},
						error: function (){
							clearInterval(thread);
							this.session_expired = true;
							mats.system_misc.reload_expired_session();
						}
					});
				}
			}, update_frequency);
		} else {
			let timeout = parseInt(SESSION_EXPIRY_CHECK) ;
			if ((timeout > 0) && (timeout*1000 < 2147483647)){
				setTimeout(mats.system_misc.reload_expired_session, timeout * 1000);
			}
		}
	}

}

mats.system.loader.is_current_page_persistable = function() {
	return (new mats.system_storage()).has('filters');
};

